export const ALL_RESTAURANTS = [
  ...DC_RESTAURANTS, ...AUSTIN_RESTAURANTS,
  ...ATLANTA_RESTAURANTS, ...AUSTIN_RESTAURANTS, ...BALTIMORE_RESTAURANTS, ...BOSTON_RESTAURANTS, ...CHARLOTTE_RESTAURANTS, ...CHICAGO_RESTAURANTS, ...COLUMBUS_RESTAURANTS, ...DALLAS_RESTAURANTS, ...DC_RESTAURANTS, ...DENVER_RESTAURANTS, ...DETROIT_RESTAURANTS, ...HOUSTON_RESTAURANTS, ...INDIANAPOLIS_RESTAURANTS, ...LA_RESTAURANTS, ...MIAMI_RESTAURANTS, ...MILWAUKEE_RESTAURANTS, ...MINNEAPOLIS_RESTAURANTS, ...NASHVILLE_RESTAURANTS, ...NOLA_RESTAURANTS, ...NYC_RESTAURANTS, ...PHILLY_RESTAURANTS, ...PHOENIX_RESTAURANTS, ...PITTSBURGH_RESTAURANTS, ...PORTLAND_RESTAURANTS, ...RALEIGH_RESTAURANTS, ...SANDIEGO_RESTAURANTS, ...SEATTLE_RESTAURANTS, ...SF_RESTAURANTS, ...STLOUIS_RESTAURANTS, ...TAMPA_RESTAURANTS,
];

export function getRestaurantsForMetro(metro: string): RestaurantData[] {
  return ALL_RESTAURANTS.filter(r => r.metros.includes(metro));
}

export function findRestaurantData(name: string, metro?: string): RestaurantData | null {
  const normalized = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  const pool = metro ? getRestaurantsForMetro(metro) : ALL_RESTAURANTS;
  const exact = pool.find(r => r.slug === normalized);
  if (exact) return exact;
  const contains = pool.find(r => normalized.includes(r.slug) || r.slug.includes(normalized));
  if (contains) return contains;
  return null;
}

export function getDirectOrderUrl(restaurant: RestaurantData): string | null {
  return restaurant.toastUrl ?? restaurant.squareUrl ?? restaurant.websiteOrderUrl ?? null;
}
